import React, { useState, useEffect } from 'react';
import { layers } from '../constants'; // Importa la matriz de datos de capas

import "../styles/CustomParallax.css";

const CustomParallax = () => {
  const [scrollPercentage, setScrollPercentage] = useState(0);

  useEffect(() => {
    const handleScroll = () => {
      const scrollHeight = document.documentElement.scrollHeight - document.documentElement.clientHeight;
      const scrollTop = window.scrollY;
      const percentage = (scrollTop / scrollHeight) * 100;
      setScrollPercentage(percentage);
    };

    // Agrega un event listener para escuchar el evento de scroll
    window.addEventListener('scroll', handleScroll);

    // Remueve el event listener cuando el componente se desmonta
    return () => {
      window.removeEventListener('scroll', handleScroll);
    };
  }, []); // Solo se ejecuta una vez al montar el componente

  return (
    <div className="parallax-container">
      {layers.map((layer, index) => (
        <ParallaxElement
          key={index}
          imgSrc={layer.imgSrc}
          imgOffset={layer.imgOffset}
          imgSpeed={layer.imgSpeed}
          scrollPercentage={scrollPercentage}
        />
      ))}
    </div>
  );
};

const ParallaxElement = ({ imgSrc, imgOffset, imgSpeed, scrollPercentage }) => {
  const translateX = -((scrollPercentage * imgSpeed) + parseFloat(imgOffset));

  return (
    <div
      className="parallax-element"
      style={{ backgroundImage: `url(${imgSrc})`, transform: `translateX(${translateX}px)` }}
    />
  );
};

export default CustomParallax;
